import React from 'react';
import TodoInputForm from '../components/TodoInputForm';
import TodoListPanel from '../components/TodoListPanel';
import { useTodos } from '../hooks/useTodos';

export default function Home() {
  const { todos, addTodo, toggleTodo } = useTodos();

  return (
    <main className="min-h-screen bg-slate-50 px-6 py-10">
      <section className="mx-auto max-w-3xl space-y-8">
        <div className="space-y-3 text-center">
          <p className="text-sm font-medium uppercase tracking-[0.2em] text-blue-600">Todo App</p>
          <h1 className="text-4xl font-bold tracking-tight text-slate-950">Plan your day with clarity</h1>
          <p className="text-slate-500">Create todos, complete tasks, and keep your workflow focused.</p>
        </div>
        <TodoInputForm onCreateTodo={addTodo} />
        <TodoListPanel todos={todos} onToggleTodo={toggleTodo} />
      </section>
    </main>
  );
}
